export const CORS_PROXY = 'https://cors-anywhere.herokuapp.com/';

import { JIKAN_API_BASE } from '../constants';
import { Anime, Episode } from '../types';

export const searchAnime = async (query: string): Promise<Anime[]> => {
  const response = await fetch(`${JIKAN_API_BASE}/anime?q=${encodeURIComponent(query)}&limit=20`);
  if (!response.ok) throw new Error('Failed to fetch anime');
  const data = await response.json();
  return data.data;
};

export const getAnimeEpisodes = async (malId: number): Promise<Episode[]> => {
  const response = await fetch(`${JIKAN_API_BASE}/anime/${malId}/episodes`);
  if (!response.ok) throw new Error('Failed to fetch episodes');
  const data = await response.json();
  return data.data.map((ep: any) => ({
    mal_id: ep.mal_id,
    title: ep.title,
    episode_id: ep.mal_id.toString(),
    number: ep.mal_id,
    aired: ep.aired
  }));
};

import { ANILIST_API_BASE } from '../constants';

export const getAniListAuthUrl = (clientId: string, redirectUri: string) => {
  return `https://anilist.co/api/v2/oauth/authorize?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=token`;
};

export const updateAniListProgress = async (token: string, mediaId: number, progress: number) => {
  const query = `
    mutation ($mediaId: Int, $progress: Int) {
      SaveMediaListEntry (mediaId: $mediaId, progress: $progress) {
        id
        progress
      }
    }
  `;

  const variables = { mediaId, progress };

  const response = await fetch(ANILIST_API_BASE, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      'Authorization': `Bearer ${token}`
    },
    body: JSON.stringify({ query, variables })
  });

  return response.json();
};

export const fetchViewer = async (token: string) => {
  const query = `
    query {
      Viewer {
        id
        name
        avatar {
          large
        }
      }
    }
  `;

  const response = await fetch(ANILIST_API_BASE, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      'Authorization': `Bearer ${token}`
    },
    body: JSON.stringify({ query })
  });

  const data = await response.json();
  return data.data.Viewer;
};

import { SourcePlugin, SourceType, SourceResult } from '../types';

export const resolveSource = async (
  plugin: SourcePlugin,
  animeId: string,
  episodeNumber: number
): Promise<SourceResult> => {
  // In a real implementation, we'd fetch from the plugin's endpoints
  // For this demo, we simulate the resolution logic

  if (plugin.type === SourceType.EMBED) {
    const url = plugin.getVideoUrlTemplate
      .replace('{animeId}', animeId)
      .replace('{episodeNumber}', episodeNumber.toString());

    return {
      url,
      type: SourceType.EMBED,
      pluginName: plugin.name
    };
  }

  // Direct HLS simulation (calling a real public API like Consumet for logic demonstration)
  try {
    const epSearch = await fetch(`https://api.consumet.org/anime/gogoanime/watch/spy-x-family-episode-${episodeNumber}`);
    const data = await epSearch.json();
    return {
      url: data.sources[0].url,
      type: SourceType.DIRECT,
      pluginName: plugin.name
    };
  } catch (e) {
    // Fallback URL
    return {
      url: 'https://test-streams.mux.dev/x36xhzz/x36xhzz.m3u8',
      type: SourceType.DIRECT,
      pluginName: plugin.name
    };
  }
};

