import React, { useEffect, useRef, useState, useCallback } from 'react';
import { SourceResult, SourceType } from '../types';
import { PlayIcon, PauseIcon } from './Icons';

interface PlayerProps {
  source: SourceResult;
  title: string;
  onProgress: (percent: number) => void;
  onComplete: () => void;
}

const Player: React.FC<PlayerProps> = ({ source, title, onProgress, onComplete }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [showControls, setShowControls] = useState(true);
  const controlsTimer = useRef<number | null>(null);

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      const current = videoRef.current.currentTime;
      const total = videoRef.current.duration;
      setCurrentTime(current);
      setDuration(total);

      const percent = (current / total) * 100;
      onProgress(percent);
      if (percent >= 90) onComplete();
    }
  };

  useEffect(() => {
    if (source.type === SourceType.DIRECT && videoRef.current) {
      const video = videoRef.current;
      // @ts-ignore (Hls is globally loaded in index.html)
      if (Hls.isSupported()) {
        // @ts-ignore
        const hls = new Hls();
        hls.loadSource(source.url);
        hls.attachMedia(video);
        hls.on('hlsManifestParsed', () => {
          video.play();
          setIsPlaying(true);
        });
        return () => hls.destroy();
      } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
        video.src = source.url;
        video.addEventListener('loadedmetadata', () => {
          video.play();
          setIsPlaying(true);
        });
      }
    }
  }, [source]);

  const togglePlay = () => {
    if (videoRef.current) {
      if (isPlaying) videoRef.current.pause();
      else videoRef.current.play();
      setIsPlaying(!isPlaying);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleMouseMove = () => {
    setShowControls(true);
    if (controlsTimer.current) window.clearTimeout(controlsTimer.current);
    controlsTimer.current = window.setTimeout(() => setShowControls(false), 3000);
  };

  if (source.type === SourceType.EMBED) {
    return (
      <div className="relative aspect-video w-full bg-black rounded-lg overflow-hidden shadow-2xl">
        <iframe
          src={source.url}
          className="w-full h-full border-0"
          allowFullScreen
          referrerPolicy="no-referrer"
          sandbox="allow-scripts allow-same-origin"
        />
        <div className="absolute top-4 left-4 bg-black/60 px-3 py-1 rounded text-xs text-white/80">
          Source: {source.pluginName} (Embedded)
        </div>
      </div>
    );
  }

  return (
    <div 
      className="relative aspect-video w-full bg-black rounded-lg overflow-hidden shadow-2xl group cursor-none"
      onMouseMove={handleMouseMove}
      style={{ cursor: showControls ? 'default' : 'none' }}
    >
      <video
        ref={videoRef}
        className="w-full h-full"
        onTimeUpdate={handleTimeUpdate}
        onClick={togglePlay}
      />

      {/* Custom Controls */}
      <div className={`absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/90 to-transparent p-4 transition-opacity duration-300 ${showControls ? 'opacity-100' : 'opacity-0'}`}>
        <div className="mb-4 h-1.5 w-full bg-white/20 rounded-full cursor-pointer relative">
          <div 
            className="absolute top-0 left-0 h-full bg-blue-500 rounded-full"
            style={{ width: `${(currentTime / duration) * 100}%` }}
          />
        </div>

        <div className="flex items-center justify-between text-white">
          <div className="flex items-center gap-4">
            <button onClick={togglePlay} className="hover:text-blue-400 transition-colors">
              {isPlaying ? <PauseIcon /> : <PlayIcon />}
            </button>
            <span className="text-sm font-medium">
              {formatTime(currentTime)} / {formatTime(duration)}
            </span>
          </div>
          <div className="flex items-center gap-3">
             <span className="text-xs text-white/60 bg-white/10 px-2 py-0.5 rounded">HLS</span>
             <span className="text-sm font-semibold">{title}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Player;

import React, { useState, useEffect, useCallback } from 'react';
import { Anime, Episode, SourcePlugin, SourceResult, User } from './types';
import { DEFAULT_PLUGINS } from './constants';
import { searchAnime, getAnimeEpisodes } from './services/jikanService';
import { resolveSource } from './services/pluginService';
import { fetchViewer, updateAniListProgress } from './services/anilistService';
import Player from './components/Player';
import { SearchIcon, CloseIcon, PlayIcon, UserIcon } from './components/Icons';

const App: React.FC = () => {
  // State
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Anime[]>([]);
  const [selectedAnime, setSelectedAnime] = useState<Anime | null>(null);
  const [episodes, setEpisodes] = useState<Episode[]>([]);
  const [selectedEpisode, setSelectedEpisode] = useState<Episode | null>(null);
  const [activeSource, setActiveSource] = useState<SourceResult | null>(null);
  const [plugins, setPlugins] = useState<SourcePlugin[]>(DEFAULT_PLUGINS);
  const [activePluginId, setActivePluginId] = useState<string>(DEFAULT_PLUGINS[0].id);
  const [user, setUser] = useState<User | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [token, setToken] = useState<string | null>(localStorage.getItem('anilist_token'));

  // Auth Handling
  useEffect(() => {
    const hash = window.location.hash;
    if (hash.includes('access_token')) {
      const newToken = new URLSearchParams(hash.substring(1)).get('access_token');
      if (newToken) {
        setToken(newToken);
        localStorage.setItem('anilist_token', newToken);
        window.location.hash = '';
      }
    }
  }, []);

  useEffect(() => {
    if (token) {
      fetchViewer(token).then(setUser).catch(() => {
        setToken(null);
        localStorage.removeItem('anilist_token');
      });
    }
  }, [token]);

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!searchQuery.trim()) return;
    setIsSearching(true);
    try {
      const results = await searchAnime(searchQuery);
      setSearchResults(results);
    } catch (err) {
      console.error(err);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSelectAnime = async (anime: Anime) => {
    setSelectedAnime(anime);
    setSearchResults([]);
    setSearchQuery('');
    try {
      const eps = await getAnimeEpisodes(anime.mal_id);
      setEpisodes(eps);
    } catch (err) {
      console.error(err);
    }
  };

  const handleSelectEpisode = async (episode: Episode) => {
    setSelectedEpisode(episode);
    const plugin = plugins.find(p => p.id === activePluginId) || plugins[0];
    const source = await resolveSource(plugin, selectedAnime!.mal_id.toString(), episode.number);
    setActiveSource(source);
  };

  const handleSwitchSource = async (pluginId: string) => {
    setActivePluginId(pluginId);
    if (selectedEpisode && selectedAnime) {
      const plugin = plugins.find(p => p.id === pluginId)!;
      const source = await resolveSource(plugin, selectedAnime.mal_id.toString(), selectedEpisode.number);
      setActiveSource(source);
    }
  };

  const onProgressUpdate = (percent: number) => {
    // Logic for partial sync could go here
  };

  const onEpisodeComplete = useCallback(() => {
    if (token && selectedAnime && selectedEpisode) {
      updateAniListProgress(token, selectedAnime.mal_id, selectedEpisode.number);
      console.log('Progress synced with AniList');
    }
  }, [token, selectedAnime, selectedEpisode]);

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-slate-900 border-b border-white/10 px-6 py-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => {
          setSelectedAnime(null);
          setSelectedEpisode(null);
          setActiveSource(null);
        }}>
          <div className="bg-blue-600 p-2 rounded-lg">
            <PlayIcon className="text-white" size={24} />
          </div>
          <h1 className="text-xl font-bold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-500">
            ZENITH PLAYER
          </h1>
        </div>

        <form onSubmit={handleSearch} className="flex-1 max-w-xl mx-8 relative hidden md:block">
          <input
            type="text"
            placeholder="Search anime..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-slate-800 border border-white/10 rounded-full px-6 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-sm"
          />
          <button type="submit" className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white transition-colors">
            <SearchIcon size={18} />
          </button>
        </form>

        <div className="flex items-center gap-4">
          {user ? (
            <div className="flex items-center gap-3 bg-white/5 px-3 py-1.5 rounded-full border border-white/10">
              <img src={user.avatar} alt={user.name} className="w-8 h-8 rounded-full ring-2 ring-blue-500/30" />
              <span className="text-sm font-medium hidden sm:inline">{user.name}</span>
            </div>
          ) : (
            <button 
              onClick={() => window.location.href = `https://anilist.co/api/v2/oauth/authorize?client_id=22153&response_type=token`}
              className="bg-blue-600 hover:bg-blue-500 px-4 py-2 rounded-lg text-sm font-semibold transition-colors flex items-center gap-2"
            >
              <UserIcon size={18} />
              Login with AniList
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 container mx-auto px-4 py-8">
        {isSearching && (
          <div className="flex flex-col items-center justify-center py-20">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500 mb-4"></div>
            <p className="text-slate-400">Summoning anime data...</p>
          </div>
        )}

        {searchResults.length > 0 && !selectedAnime && (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 xl:grid-cols-6 gap-6">
            {searchResults.map(anime => (
              <div 
                key={anime.mal_id} 
                className="group cursor-pointer bg-slate-800/50 rounded-xl overflow-hidden border border-white/5 hover:border-blue-500/50 transition-all hover:-translate-y-1"
                onClick={() => handleSelectAnime(anime)}
              >
                <div className="aspect-[3/4] relative overflow-hidden">
                  <img src={anime.images.jpg.large_image_url} alt={anime.title} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-4">
                    <button className="w-full bg-blue-600 py-2 rounded-lg text-sm font-bold shadow-lg">View Episodes</button>
                  </div>
                </div>
                <div className="p-3">
                  <h3 className="text-sm font-semibold line-clamp-1 group-hover:text-blue-400 transition-colors">{anime.title}</h3>
                  <div className="flex items-center gap-2 mt-1">
                    <span className="text-xs text-slate-400 font-medium">{anime.year || 'N/A'}</span>
                    <span className="w-1 h-1 rounded-full bg-slate-600"></span>
                    <span className="text-xs text-yellow-500 font-bold">★ {anime.score}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {selectedAnime && (
          <div className="flex flex-col lg:flex-row gap-8">
            <div className="flex-1">
              {activeSource ? (
                <div className="space-y-6">
                  <Player 
                    source={activeSource} 
                    title={`${selectedAnime.title} - Episode ${selectedEpisode?.number}`}
                    onProgress={onProgressUpdate}
                    onComplete={onEpisodeComplete}
                  />

                  <div className="bg-slate-800/50 p-6 rounded-xl border border-white/5">
                    <div className="flex items-center justify-between mb-4">
                      <h2 className="text-xl font-bold">{selectedEpisode?.title || `Episode ${selectedEpisode?.number}`}</h2>
                      <div className="flex gap-2">
                        {plugins.map(p => (
                          <button
                            key={p.id}
                            onClick={() => handleSwitchSource(p.id)}
                            className={`px-3 py-1 rounded text-xs font-bold transition-colors ${activePluginId === p.id ? 'bg-blue-600 text-white' : 'bg-white/5 text-slate-400 hover:bg-white/10'}`}
                          >
                            {p.name}
                          </button>
                        ))}
                      </div>
                    </div>
                    <p className="text-slate-400 text-sm leading-relaxed">{selectedAnime.synopsis}</p>
                  </div>
                </div>
              ) : (
                <div className="flex flex-col md:flex-row gap-8">
                   <div className="w-full md:w-64 flex-shrink-0">
                     <img src={selectedAnime.images.jpg.large_image_url} alt={selectedAnime.title} className="w-full rounded-xl shadow-2xl" />
                   </div>
                   <div className="flex-1">
                     <h2 className="text-3xl font-bold mb-2">{selectedAnime.title}</h2>
                     <div className="flex gap-3 mb-6">
                       <span className="bg-blue-600/20 text-blue-400 px-3 py-1 rounded-full text-xs font-bold border border-blue-500/20">{selectedAnime.status}</span>
                       <span className="bg-yellow-600/20 text-yellow-400 px-3 py-1 rounded-full text-xs font-bold border border-yellow-500/20">Score: {selectedAnime.score}</span>
                       <span className="bg-slate-700/50 text-slate-300 px-3 py-1 rounded-full text-xs font-bold">{selectedAnime.episodes} Episodes</span>
                     </div>
                     <p className="text-slate-300 leading-relaxed line-clamp-6 mb-8">{selectedAnime.synopsis}</p>

                     <div className="space-y-4">
                       <h3 className="text-lg font-bold">Select an Episode</h3>
                       <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                         {episodes.map(ep => (
                           <button
                             key={ep.mal_id}
                             onClick={() => handleSelectEpisode(ep)}
                             className="bg-slate-800 hover:bg-blue-600/20 border border-white/5 hover:border-blue-500/50 p-3 rounded-lg text-left transition-all group"
                           >
                             <div className="text-xs text-slate-500 mb-1 group-hover:text-blue-400 transition-colors">EPISODE {ep.number}</div>
                             <div className="text-sm font-semibold truncate">{ep.title || 'Untitled'}</div>
                           </button>
                         ))}
                       </div>
                     </div>
                   </div>
                </div>
              )}
            </div>

            {activeSource && (
              <div className="w-full lg:w-80 space-y-4">
                <h3 className="text-lg font-bold px-2">Episode List</h3>
                <div className="max-h-[600px] overflow-y-auto pr-2 space-y-2 custom-scrollbar">
                  {episodes.map(ep => (
                    <button
                      key={ep.mal_id}
                      onClick={() => handleSelectEpisode(ep)}
                      className={`w-full flex items-center gap-3 p-2 rounded-lg transition-colors border ${selectedEpisode?.mal_id === ep.mal_id ? 'bg-blue-600/10 border-blue-500/50' : 'bg-slate-800/30 border-transparent hover:bg-slate-800'}`}
                    >
                      <div className={`w-10 h-10 flex-shrink-0 flex items-center justify-center rounded font-bold text-sm ${selectedEpisode?.mal_id === ep.mal_id ? 'bg-blue-600 text-white' : 'bg-slate-700 text-slate-400'}`}>
                        {ep.number}
