import { JIKAN_API_BASE } from '../constants';
import { Anime, Episode } from '../types';

export const searchAnime = async (query: string): Promise<Anime[]> => {
  const response = await fetch(`${JIKAN_API_BASE}/anime?q=${encodeURIComponent(query)}&limit=20`);
  if (!response.ok) throw new Error('Failed to fetch anime');
  const data = await response.json();
  return data.data;
};

export interface EpisodesResponse {
  data: Episode[];
  pagination: {
    last_visible_page: number;
    has_next_page: boolean;
  };
}

export const getAnimeEpisodes = async (malId: number, page: number = 1): Promise<EpisodesResponse> => {
  const response = await fetch(`${JIKAN_API_BASE}/anime/${malId}/episodes?page=${page}`);
  if (!response.ok) throw new Error('Failed to fetch episodes');
  const data = await response.json();

  return {
    data: data.data.map((ep: any) => ({
      mal_id: ep.mal_id,
      title: ep.title,
      episode_id: ep.mal_id.toString(),
      number: ep.mal_id,
      aired: ep.aired
    })),
    pagination: data.pagination
  };
};

import { SourcePlugin, SourceType, SourceResult } from '../types';

export const resolveSource = async (
  plugin: SourcePlugin,
  animeId: string,
  episodeNumber: number
): Promise<SourceResult> => {
  if (plugin.type === SourceType.EMBED) {
    const url = plugin.getVideoUrlTemplate
      .replace('{animeId}', animeId)
      .replace('{episodeNumber}', episodeNumber.toString());

    return {
      url,
      type: SourceType.EMBED,
      pluginName: plugin.name,
      category: plugin.category
    };
  }

  try {
    // In a real production app, we would use the plugin's getVideoUrlTemplate
    // For demo, we simulate fetching an HLS stream.
    // We use a known test HLS stream if the API fails
    const mockHls = 'https://test-streams.mux.dev/x36xhzz/x36xhzz.m3u8';

    return {
      url: mockHls,
      type: SourceType.DIRECT,
      pluginName: plugin.name,
      category: plugin.category
    };
  } catch (e) {
    return {
      url: 'https://test-streams.mux.dev/x36xhzz/x36xhzz.m3u8',
      type: SourceType.DIRECT,
      pluginName: plugin.name,
      category: plugin.category
    };
  }
};

import React from 'react';
import { MediaPlayer, MediaProvider, Track } from '@vidstack/react';
import { defaultLayoutIcons, DefaultVideoLayout } from '@vidstack/react/player/layouts/default';
import { SourceResult, SourceType } from '../types';

interface PlayerProps {
  source: SourceResult;
  title: string;
  onProgress: (percent: number) => void;
  onComplete: () => void;
}

const Player: React.FC<PlayerProps> = ({ source, title, onProgress, onComplete }) => {
  const onTimeUpdate = (detail: { currentTime: number; duration: number }) => {
    const { currentTime, duration } = detail;
    if (duration > 0) {
      const percent = (currentTime / duration) * 100;
      onProgress(percent);
      if (percent >= 90) {
        onComplete();
      }
    }
  };

  if (source.type === SourceType.EMBED) {
    return (
      <div className="relative aspect-video w-full bg-black rounded-lg overflow-hidden shadow-2xl">
        <iframe
          src={source.url}
          className="w-full h-full border-0"
          allowFullScreen
          referrerPolicy="no-referrer"
          sandbox="allow-scripts allow-same-origin"
        />
        <div className="absolute top-4 left-4 bg-black/60 px-3 py-1 rounded text-xs text-white/80">
          Source: {source.pluginName} ({source.category})
        </div>
      </div>
    );
  }

  return (
    <div className="relative aspect-video w-full bg-black rounded-lg overflow-hidden shadow-2xl">
      <MediaPlayer
        title={title}
        src={source.url}
        onTimeUpdate={(e) => onTimeUpdate(e.detail)}
        onEnd={onComplete}
        crossOrigin
        playsInline
        className="w-full h-full"
      >
        <MediaProvider />
        <DefaultVideoLayout icons={defaultLayoutIcons} />
      </MediaPlayer>
    </div>
  );
};

