import React from 'react';
import { MediaPlayer, MediaProvider, Poster } from '@vidstack/react';
import { defaultLayoutIcons, DefaultVideoLayout } from '@vidstack/react/player/layouts/default';
import { SourceResult, SourceType } from '../types';

interface PlayerProps {
  source: SourceResult;
  title: string;
  poster?: string;
  onProgress: (percent: number) => void;
  onComplete: () => void;
}

const Player: React.FC<PlayerProps> = ({ source, title, poster, onProgress, onComplete }) => {
  const onTimeUpdate = (detail: { currentTime: number; duration: number }) => {
    const { currentTime, duration } = detail;
    if (duration > 0) {
      const percent = (currentTime / duration) * 100;
      onProgress(percent);
      if (percent >= 90) {
        onComplete();
      }
    }
  };

  if (source.type === SourceType.EMBED) {
    return (
      <div className="relative aspect-video w-full bg-black rounded-xl overflow-hidden shadow-2xl">
        <iframe
          src={source.url}
          className="w-full h-full border-0"
          allowFullScreen
          referrerPolicy="no-referrer"
          sandbox="allow-scripts allow-same-origin"
        />
        <div className="absolute top-4 left-4 bg-black/60 px-3 py-1 rounded text-xs text-white/80">
          Source: {source.pluginName} ({source.category})
        </div>
      </div>
    );
  }

  return (
    <div className="relative aspect-video w-full bg-black rounded-xl overflow-hidden shadow-2xl">
      <MediaPlayer
        title={title}
        src={source.url}
        onTimeUpdate={(e) => onTimeUpdate(e.detail)}
        onEnded={onComplete}
        crossOrigin
        playsInline
        className="w-full h-full"
      >
        <MediaProvider>
           {poster && <Poster src={poster} alt={title} className="vds-poster" />}
        </MediaProvider>
        <DefaultVideoLayout icons={defaultLayoutIcons} />
      </MediaPlayer>
    </div>
  );
};

export default Player;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Anime, Episode, SourcePlugin, SourceResult, User, SourceCategory } from './types';
import { DEFAULT_PLUGINS } from './constants';
import { searchAnime, getAnimeEpisodes } from './services/jikanService';
import { fetchViewer, updateAniListProgress } from './services/anilistService';
import Player from './components/Player';
import { SearchIcon, PlayIcon, UserIcon } from './components/Icons';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Anime[]>([]);
  const [selectedAnime, setSelectedAnime] = useState<Anime | null>(null);

  // Episode Batch Loading (Mocking 366 for Bleach test)
  const [allEpisodes, setAllEpisodes] = useState<Episode[]>([]);
  const [displayedEpisodes, setDisplayedEpisodes] = useState<Episode[]>([]);
  const [batchPage, setBatchPage] = useState(1);
  const BATCH_SIZE = 100;

  const [selectedEpisode, setSelectedEpisode] = useState<Episode | null>(null);
  const [activeSource, setActiveSource] = useState<SourceResult | null>(null);
  const [plugins] = useState<SourcePlugin[]>(DEFAULT_PLUGINS);
  const [activePluginId, setActivePluginId] = useState<string>(DEFAULT_PLUGINS[0].id);
  const [user, setUser] = useState<User | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [token, setToken] = useState<string | null>(localStorage.getItem('anilist_token'));

  // Auth Handling
  useEffect(() => {
    const hash = window.location.hash;
    if (hash.includes('access_token')) {
      const newToken = new URLSearchParams(hash.substring(1)).get('access_token');
      if (newToken) {
        setToken(newToken);
        localStorage.setItem('anilist_token', newToken);
        window.location.hash = '';
      }
    }
  }, []);

  useEffect(() => {
    if (token) {
      fetchViewer(token).then(setUser).catch(() => {
        setToken(null);
        localStorage.removeItem('anilist_token');
      });
    }
  }, [token]);

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!searchQuery.trim()) return;
    setIsSearching(true);
    try {
      const results = await searchAnime(searchQuery);
      setSearchResults(results);
    } catch (err) {
      console.error(err);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSelectAnime = async (anime: Anime) => {
    setSelectedAnime(anime);
    setSearchResults([]);
    setSearchQuery('');

    // Mock 366 episodes for "Bleach" style pagination
    const mockCount = 366;
    const mocks: Episode[] = Array.from({ length: mockCount }, (_, i) => ({
      mal_id: i + 1,
      number: i + 1,
      episode_id: `ep-${i + 1}`,
      title: `The Thousand Year Blood War - Part ${i + 1}`,
      aired: new Date().toISOString()
    }));

    setAllEpisodes(mocks);
    setDisplayedEpisodes(mocks.slice(0, BATCH_SIZE));
    setBatchPage(1);
  };

  const loadMoreEpisodes = () => {
    const nextPage = batchPage + 1;
    const end = nextPage * BATCH_SIZE;
    setDisplayedEpisodes(allEpisodes.slice(0, end));
    setBatchPage(nextPage);
  };

  const handleSelectEpisode = useCallback(async (episode: Episode) => {
    setSelectedEpisode(episode);
    const plugin = plugins.find(p => p.id === activePluginId) || plugins[0];
    setActiveSource({
      url: plugin.url,
      type: plugin.type,
      pluginName: plugin.name,
      label: plugin.label,
      category: plugin.category
    });
  }, [activePluginId, plugins]);

  const handleSwitchSource = (pluginId: string) => {
    setActivePluginId(pluginId);
    const plugin = plugins.find(p => p.id === pluginId)!;
    if (selectedEpisode) {
      setActiveSource({
        url: plugin.url,
        type: plugin.type,
        pluginName: plugin.name,
        label: plugin.label,
        category: plugin.category
      });
    }
  };

  const onEpisodeComplete = useCallback(() => {
    if (token && selectedAnime && selectedEpisode) {
      updateAniListProgress(token, selectedAnime.mal_id, selectedEpisode.number);
      console.log('Progress synced with AniList');
    }
  }, [token, selectedAnime, selectedEpisode]);

  // Grouped plugins for selection UI
  const groupedPlugins = useMemo(() => {
    const groups: Record<SourceCategory, SourcePlugin[]> = {
      hardsub: [],
      softsub: [],
      dub: []
    };
    plugins.forEach(p => {
      groups[p.category].push(p);
    });
    return groups;
  }, [plugins]);

  return (
    <div className="min-h-screen flex flex-col bg-slate-950">
      {/* Header */}
      <header className="bg-slate-900/80 backdrop-blur-md border-b border-white/10 px-6 py-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => {
          setSelectedAnime(null);
          setSelectedEpisode(null);
          setActiveSource(null);
          setAllEpisodes([]);
        }}>
          <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-500/20">
            <PlayIcon className="text-white" size={24} />
          </div>
          <h1 className="text-xl font-black tracking-tighter bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-500">
            ZENITH
          </h1>
        </div>

        <form onSubmit={handleSearch} className="flex-1 max-w-xl mx-8 relative hidden md:block">
          <input
            type="text"
            placeholder="Search anime database..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-slate-800/50 border border-white/10 rounded-full px-6 py-2.5 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-sm backdrop-blur-sm"
          />
          <button type="submit" className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white transition-colors">
            <SearchIcon size={18} />
          </button>
        </form>

        <div className="flex items-center gap-4">
          {user ? (
            <div className="flex items-center gap-3 bg-white/5 px-3 py-1.5 rounded-full border border-white/10">
              <img src={user.avatar} alt={user.name} className="w-8 h-8 rounded-full ring-2 ring-blue-500/30" />
              <span className="text-sm font-medium hidden sm:inline">{user.name}</span>
            </div>
          ) : (
            <button 
              onClick={() => window.location.href = `https://anilist.co/api/v2/oauth/authorize?client_id=22153&response_type=token&redirect_uri=${encodeURIComponent(window.location.origin)}`}
              className="bg-blue-600 hover:bg-blue-500 px-5 py-2.5 rounded-xl text-sm font-bold transition-all flex items-center gap-2 shadow-lg shadow-blue-600/20"
            >
              <UserIcon size={18} />
              AniList Login
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 container mx-auto px-4 py-8">
        {isSearching && (
          <div className="flex flex-col items-center justify-center py-24">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500 mb-6"></div>
            <p className="text-slate-400 font-medium">Summoning your favorite titles...</p>
          </div>
        )}

        {searchResults.length > 0 && !selectedAnime && (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 xl:grid-cols-6 gap-6">
            {searchResults.map(anime => (
              <div 
                key={anime.mal_id} 
                className="group cursor-pointer bg-slate-800/30 rounded-2xl overflow-hidden border border-white/5 hover:border-blue-500/50 transition-all hover:-translate-y-2 shadow-xl"
                onClick={() => handleSelectAnime(anime)}
              >
                <div className="aspect-[3/4] relative overflow-hidden">
                  <img src={anime.images.jpg.large_image_url} alt={anime.title} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                  <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-4">
                    <button className="w-full bg-blue-600 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest shadow-lg">Play Now</button>
                  </div>
                </div>
                <div className="p-4">
                  <h3 className="text-sm font-bold line-clamp-1 group-hover:text-blue-400 transition-colors">{anime.title}</h3>
                  <div className="flex items-center gap-2 mt-2">
                    <span className="text-[10px] font-black bg-white/5 px-2 py-0.5 rounded text-slate-400 uppercase">{anime.year || 'N/A'}</span>
                    <span className="text-xs text-yellow-500 font-bold">★ {anime.score}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {selectedAnime && (
          <div className="flex flex-col lg:flex-row gap-8">
            <div className="flex-1 space-y-6">
              {activeSource ? (
                <div className="space-y-6">
                  <Player 
                    source={activeSource} 
                    title={`${selectedAnime.title} - Episode ${selectedEpisode?.number}`}
                    poster={selectedAnime.images.jpg.large_image_url}
                    onProgress={(p) => console.log('Progress:', p)}
                    onComplete={onEpisodeComplete}
                  />

                  <div className="bg-slate-900/50 p-6 rounded-2xl border border-white/5 backdrop-blur-sm">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                      <div>
                        <h2 className="text-2xl font-black mb-1">{selectedEpisode?.title}</h2>
                        <p className="text-sm text-slate-400 uppercase font-black tracking-widest">Episode {selectedEpisode?.number}</p>
                      </div>

                      {/* Batch Source Selector Group */}
                      <div className="flex flex-wrap gap-4 bg-black/40 p-4 rounded-2xl border border-white/5">
                        {Object.entries(groupedPlugins).map(([category, categoryPlugins]) => {
                          if (categoryPlugins.length === 0) return null;
                          return (
                            <div key={category} className="flex flex-col gap-1.5 min-w-[120px]">
                              <span className="text-[10px] uppercase font-black text-slate-500 tracking-widest">{category}</span>
                              <select 
                                className="bg-slate-800 text-white text-xs font-bold rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500 border border-white/10 appearance-none cursor-pointer hover:bg-slate-700 transition-colors"
                                value={categoryPlugins.some(p => p.id === activePluginId) ? activePluginId : ""}
                                onChange={(e) => handleSwitchSource(e.target.value)}
                              >
                                {categoryPlugins.map(p => (
                                  <option key={p.id} value={p.id}>{p.label}</option>
                                ))}
                              </select>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                </div>
