                             <div className="text-[10px] font-black text-slate-500 group-hover:text-blue-400 uppercase tracking-widest">EP {ep.number}</div>
                             <div className="text-xs font-bold truncate text-slate-200 group-hover:text-white">{ep.title}</div>
                           </button>
