            )}
          </div>
        )}

        {!selectedAnime && !isSearching && (
          <div className="text-center py-40 max-w-2xl mx-auto space-y-8">
             <div className="relative inline-block">
                <div className="absolute inset-0 bg-blue-500/20 blur-3xl rounded-full"></div>
                <div className="relative p-8 bg-slate-900 rounded-full border border-white/5 shadow-2xl">
                   <PlayIcon size={80} className="text-blue-500" />
