             </div>
             <h2 className="text-5xl font-black tracking-tighter">Your Anime, <span className="text-blue-500">Perfected.</span></h2>
             <p className="text-slate-400 font-medium text-lg leading-relaxed">Experience a high-performance streaming interface. Grouped sources, batch episode loading, and AniList synchronization in one minimalist dashboard.</p>
             <div className="flex items-center justify-center gap-4">
                <button onClick={() => {setSearchQuery('Bleach'); handleSearch();}} className="bg-blue-600 hover:bg-blue-500 px-10 py-4 rounded-2xl text-sm font-black uppercase tracking-widest transition-all shadow-2xl shadow-blue-600/30">
                  Search Bleach
                </button>
                <button className="bg-white/5 hover:bg-white/10 px-10 py-4 rounded-2xl text-sm font-black uppercase tracking-widest transition-all border border-white/10">
                  Documentation
                </button>
             </div>
          </div>
        )}
      </main>

      <footer className="bg-slate-950/95 border-t border-white/5 py-10 text-center">
        <p className="text-[10px] text-slate-600 font-black uppercase tracking-[0.2em]">
          Zenith Player Prototype &bull; Powered by Vidstack &bull; {new Date().getFullYear()}
        </p>
      </footer>
    </div>
  );
};

