import React, { useRef, useState, useEffect } from 'react';
import { MediaPlayer, MediaProvider, Poster, type MediaPlayerInstance } from '@vidstack/react';
import { defaultLayoutIcons, DefaultVideoLayout } from '@vidstack/react/player/layouts/default';
import { SourceResult, SourceType } from '../types';

interface PlayerProps {
  source: SourceResult;
  title: string;
  poster?: string;
  onProgress: (percent: number) => void;
  onComplete: () => void;
}

const Player: React.FC<PlayerProps> = ({ source, title, poster, onProgress, onComplete }) => {
  const playerRef = useRef<MediaPlayerInstance>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [lastTime, setLastTime] = useState(0);

  // Preserve watch position when switching sources of the same episode
  useEffect(() => {
    setIsLoading(true);
    if (playerRef.current && lastTime > 0) {
      // Small delay to ensure engine is ready for seeking after source change
      const timer = setTimeout(() => {
        playerRef.current!.currentTime = lastTime;
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [source.url]);

  const onTimeUpdate = (detail: { currentTime: number; duration: number }) => {
    const { currentTime, duration } = detail;
    if (duration > 0) {
      setLastTime(currentTime);
      const percent = (currentTime / duration) * 100;
      onProgress(percent);
      if (percent >= 90) {
        onComplete();
      }
    }
  };

  const onCanPlay = () => {
    setIsLoading(false);
  };

  const hlsConfig = {
    // Handling external key requests if needed (XHR setup)
    xhrSetup: (xhr: XMLHttpRequest, url: string) => {
      // Ensure key requests have appropriate context if needed
      if (url.includes('.key')) {
        xhr.withCredentials = false; // Usually false for public AES keys unless specified
      }
    }
  };

  if (source.type === SourceType.EMBED) {
    return (
      <div className="relative aspect-video w-full bg-black rounded-xl overflow-hidden shadow-2xl">
        <iframe
          src={source.url}
          className="w-full h-full border-0"
          allowFullScreen
          referrerPolicy="no-referrer"
          sandbox="allow-scripts allow-same-origin"
        />
        <div className="absolute top-4 left-4 bg-black/60 px-3 py-1 rounded text-xs text-white/80">
          Source: {source.pluginName} ({source.category})
        </div>
      </div>
    );
  }

  return (
    <div className="relative aspect-video w-full bg-black rounded-xl overflow-hidden shadow-2xl group">
      {/* Loading Overlay */}
      {isLoading && (
        <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/80 backdrop-blur-sm transition-opacity">
          <div className="relative w-16 h-16">
            <div className="absolute inset-0 border-4 border-blue-500/20 rounded-full"></div>
            <div className="absolute inset-0 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
          <p className="mt-4 text-xs font-black uppercase tracking-[0.3em] text-blue-400 animate-pulse">Decrypting Source</p>
        </div>
      )}

      <MediaPlayer
        ref={playerRef}
        title={title}
        src={source.url}
        onTimeUpdate={(e) => onTimeUpdate(e.detail)}
        onEnded={onComplete}
        onCanPlay={onCanPlay}
        onLoading={() => setIsLoading(true)}
        crossOrigin
        playsInline
        className={`w-full h-full transition-opacity duration-500 ${isLoading ? 'opacity-0' : 'opacity-100'}`}
        hlsConfig={hlsConfig}
      >
        <MediaProvider>
           {poster && <Poster src={poster} alt={title} className="vds-poster" />}
        </MediaProvider>
        <DefaultVideoLayout icons={defaultLayoutIcons} />
      </MediaPlayer>
    </div>
  );
};

export default Player;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Anime, Episode, SourcePlugin, SourceResult, User, SourceCategory } from './types';
import { DEFAULT_PLUGINS } from './constants';
