const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Anime[]>([]);
  const [selectedAnime, setSelectedAnime] = useState<Anime | null>(null);

  // Episode Batch Loading
  const [allEpisodes, setAllEpisodes] = useState<Episode[]>([]);
  const [displayedEpisodes, setDisplayedEpisodes] = useState<Episode[]>([]);
  const [batchPage, setBatchPage] = useState(1);
  const [isAppending, setIsAppending] = useState(false);
  const BATCH_SIZE = 100;

  const [selectedEpisode, setSelectedEpisode] = useState<Episode | null>(null);
  const [activeSource, setActiveSource] = useState<SourceResult | null>(null);
  const [plugins] = useState<SourcePlugin[]>(DEFAULT_PLUGINS);
  const [activePluginId, setActivePluginId] = useState<string>(DEFAULT_PLUGINS[0].id);
  const [user, setUser] = useState<User | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [token, setToken] = useState<string | null>(localStorage.getItem('anilist_token'));

  // Auth Handling
  useEffect(() => {
    const hash = window.location.hash;
    if (hash.includes('access_token')) {
      const newToken = new URLSearchParams(hash.substring(1)).get('access_token');
      if (newToken) {
        setToken(newToken);
        localStorage.setItem('anilist_token', newToken);
        window.location.hash = '';
      }
    }
  }, []);

  useEffect(() => {
    if (token) {
      fetchViewer(token).then(setUser).catch(() => {
        setToken(null);
        localStorage.removeItem('anilist_token');
      });
    }
  }, [token]);

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!searchQuery.trim()) return;
    setIsSearching(true);
    try {
      const results = await searchAnime(searchQuery);
      setSearchResults(results);
    } catch (err) {
      console.error(err);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSelectAnime = async (anime: Anime) => {
    setSelectedAnime(anime);
    setSearchResults([]);
    setSearchQuery('');

    // Mocking 366 episodes for demonstration
    const mockCount = anime.episodes || 366;
    const mocks: Episode[] = Array.from({ length: mockCount }, (_, i) => ({
      mal_id: i + 1,
      number: i + 1,
      episode_id: `ep-${i + 1}`,
      title: `Episode Title ${i + 1}`,
      aired: new Date().toISOString()
    }));

    setAllEpisodes(mocks);
    setDisplayedEpisodes(mocks.slice(0, BATCH_SIZE));
    setBatchPage(1);
  };

  const loadMoreEpisodes = () => {
    setIsAppending(true);
    setTimeout(() => {
      const nextPage = batchPage + 1;
      const end = nextPage * BATCH_SIZE;
      // Append only
      setDisplayedEpisodes(allEpisodes.slice(0, end));
      setBatchPage(nextPage);
      setIsAppending(false);
    }, 600); // Visual feedback delay
  };

  const handleSelectEpisode = useCallback(async (episode: Episode) => {
    setSelectedEpisode(episode);
    const plugin = plugins.find(p => p.id === activePluginId) || plugins[0];
    setActiveSource({
      url: plugin.url,
      keyUrl: plugin.keyUrl,
      type: plugin.type,
      provider: plugin.provider,
      pluginName: plugin.name,
      label: plugin.label,
      category: plugin.category
    });
  }, [activePluginId, plugins]);

  const handleSwitchSource = (pluginId: string) => {
    setActivePluginId(pluginId);
    const plugin = plugins.find(p => p.id === pluginId)!;
    if (selectedEpisode) {
      setActiveSource({
        url: plugin.url,
        keyUrl: plugin.keyUrl,
        type: plugin.type,
        provider: plugin.provider,
        pluginName: plugin.name,
        label: plugin.label,
        category: plugin.category
      });
    }
  };

  const onEpisodeComplete = useCallback(() => {
    if (token && selectedAnime && selectedEpisode) {
      updateAniListProgress(token, selectedAnime.mal_id, selectedEpisode.number);
    }
  }, [token, selectedAnime, selectedEpisode]);

  const groupedPlugins = useMemo(() => {
    const groups: Record<SourceCategory, SourcePlugin[]> = {
      hardsub: [],
      softsub: [],
      dub: []
    };
    plugins.forEach(p => {
      groups[p.category].push(p);
    });
    return groups;
  }, [plugins]);

  return (
    <div className="min-h-screen flex flex-col bg-slate-950 selection:bg-blue-500/30">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-6 py-4 flex items-center justify-between sticky top-0 z-[60]">
        <div className="flex items-center gap-3 cursor-pointer group" onClick={() => {
          setSelectedAnime(null);
          setSelectedEpisode(null);
          setActiveSource(null);
        }}>
          <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-500/30 group-hover:scale-105 transition-transform">
            <PlayIcon className="text-white" size={24} />
          </div>
          <h1 className="text-2xl font-black tracking-tighter bg-clip-text text-transparent bg-gradient-to-r from-blue-400 via-indigo-400 to-purple-500">
            ZENITH
          </h1>
        </div>

        <form onSubmit={handleSearch} className="flex-1 max-w-xl mx-12 relative hidden md:block">
          <input
            type="text"
            placeholder="Search anime database..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-slate-800/40 border border-white/10 rounded-2xl px-6 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500/40 transition-all text-sm backdrop-blur-md"
          />
          <button type="submit" className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white transition-colors">
            <SearchIcon size={20} />
          </button>
        </form>

        <div className="flex items-center gap-4">
          {user ? (
            <div className="flex items-center gap-3 bg-white/5 px-4 py-2 rounded-2xl border border-white/10">
              <img src={user.avatar} alt={user.name} className="w-8 h-8 rounded-full ring-2 ring-blue-500/20" />
              <span className="text-sm font-bold hidden sm:inline">{user.name}</span>
            </div>
          ) : (
            <button 
              onClick={() => window.location.href = `https://anilist.co/api/v2/oauth/authorize?client_id=22153&response_type=token&redirect_uri=${encodeURIComponent(window.location.origin)}`}
              className="bg-slate-800 hover:bg-slate-700 px-6 py-3 rounded-2xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-3 border border-white/10"
            >
              <UserIcon size={18} />
              Connect AniList
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 container mx-auto px-4 py-10">
        {isSearching && (
          <div className="flex flex-col items-center justify-center py-32 space-y-6">
            <div className="w-16 h-16 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
            <p className="text-slate-500 font-black uppercase tracking-[0.4em] text-xs">Querying Matrix</p>
          </div>
        )}

        {searchResults.length > 0 && !selectedAnime && (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 xl:grid-cols-6 gap-8">
            {searchResults.map(anime => (
              <div 
                key={anime.mal_id} 
                className="group cursor-pointer bg-slate-900/40 rounded-3xl overflow-hidden border border-white/5 hover:border-blue-500/40 transition-all hover:-translate-y-2 shadow-2xl"
                onClick={() => handleSelectAnime(anime)}
              >
                <div className="aspect-[3/4] relative overflow-hidden">
                  <img src={anime.images.jpg.large_image_url} alt={anime.title} className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" />
                  <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-slate-950/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-6">
                    <button className="w-full bg-blue-600 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20">Watch Now</button>
                  </div>
                </div>
                <div className="p-5">
                  <h3 className="text-sm font-black line-clamp-1 group-hover:text-blue-400 transition-colors leading-tight">{anime.title}</h3>
                  <div className="flex items-center justify-between mt-3">
                    <span className="text-[10px] font-black bg-white/5 px-2.5 py-1 rounded-lg text-slate-500 uppercase tracking-tighter">{anime.year || 'N/A'}</span>
                    <span className="text-xs text-yellow-500 font-black flex items-center gap-1">★ {anime.score}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {selectedAnime && (
          <div className="flex flex-col lg:flex-row gap-12">
            <div className="flex-1 space-y-8">
              {activeSource ? (
                <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
                  <Player 
                    source={activeSource} 
                    title={`${selectedAnime.title} - EP ${selectedEpisode?.number}`}
                    poster={selectedAnime.images.jpg.large_image_url}
                    onProgress={(p) => {}}
                    onComplete={onEpisodeComplete}
                  />

                  <div className="bg-slate-900/60 p-8 rounded-3xl border border-white/5 backdrop-blur-xl">
                    <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-8">
                      <div>
                        <p className="text-xs font-black text-blue-500 uppercase tracking-[0.3em] mb-2">Streaming Episode {selectedEpisode?.number}</p>
                        <h2 className="text-3xl font-black tracking-tight">{selectedEpisode?.title}</h2>
                      </div>

                      <div className="flex flex-wrap gap-6 bg-black/40 p-6 rounded-3xl border border-white/5 shadow-inner">
                        {(Object.entries(groupedPlugins) as [SourceCategory, SourcePlugin[]][]).map(([category, categoryPlugins]) => {
                          if (categoryPlugins.length === 0) return null;
                          return (
                            <div key={category} className="flex flex-col gap-2 min-w-[150px]">
                              <span className="text-[10px] uppercase font-black text-slate-500 tracking-[0.2em] px-1">{category}</span>
                              <div className="relative group">
                                <select 
                                  className="w-full bg-slate-800/80 text-white text-[11px] font-black uppercase tracking-wider rounded-xl pl-4 pr-10 py-3.5 focus:outline-none focus:ring-2 focus:ring-blue-500/50 border border-white/10 appearance-none cursor-pointer hover:bg-slate-700 transition-all"
                                  value={categoryPlugins.some(p => p.id === activePluginId) ? activePluginId : ""}
                                  onChange={(e) => handleSwitchSource(e.target.value)}
                                >
                                  {!categoryPlugins.some(p => p.id === activePluginId) && <option value="" disabled>Select Source</option>}
                                  {categoryPlugins.map(p => (
                                    <option key={p.id} value={p.id}>{p.provider} – {p.label}</option>
                                  ))}
                                </select>
                                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 group-hover:text-white transition-colors">
                                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"></path></svg>
                                </div>
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="flex flex-col md:flex-row gap-12 animate-in fade-in duration-1000">
                   <div className="w-full md:w-80 flex-shrink-0 group">
                     <img src={selectedAnime.images.jpg.large_image_url} alt={selectedAnime.title} className="w-full rounded-[2.5rem] shadow-2xl ring-1 ring-white/10 transition-transform group-hover:scale-[1.02]" />
                   </div>
                   <div className="flex-1 space-y-10">
                     <div className="space-y-4">
                        <h2 className="text-5xl font-black tracking-tighter leading-[0.9]">{selectedAnime.title}</h2>
                        <div className="flex flex-wrap gap-3">
                          <span className="bg-blue-500/10 text-blue-400 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border border-blue-500/20">{selectedAnime.status}</span>
                          <span className="bg-yellow-500/10 text-yellow-500 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border border-yellow-500/20">★ {selectedAnime.score}</span>
                          <span className="bg-white/5 text-slate-400 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border border-white/5">{allEpisodes.length} EPISODES</span>
                        </div>
                     </div>

                     <div className="bg-slate-900/40 p-8 rounded-[2rem] border border-white/5">
                        <p className="text-slate-400 leading-relaxed text-sm font-medium">{selectedAnime.synopsis}</p>
                     </div>

                     <div className="space-y-8">
                       <div className="flex items-center justify-between border-b border-white/5 pb-6">
                         <h3 className="text-lg font-black uppercase tracking-[0.2em] text-white">Select Entry</h3>
                         <div className="flex items-center gap-3">
                           <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse"></div>
                           <span className="text-[11px] font-bold text-slate-500 uppercase tracking-widest">{displayedEpisodes.length} / {allEpisodes.length} Items</span>
                         </div>
                       </div>

                       <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-4 gap-4 max-h-[500px] overflow-y-auto pr-4 custom-scrollbar">
                         {displayedEpisodes.map(ep => (
                           <button
                             key={ep.mal_id}
                             onClick={() => handleSelectEpisode(ep)}
                             className="bg-slate-900/60 hover:bg-blue-600/10 border border-white/5 hover:border-blue-500/40 p-5 rounded-2xl text-left transition-all group relative overflow-hidden"
                           >
                             <div className="relative z-10">
                               <div className="text-[9px] font-black text-slate-500 group-hover:text-blue-400 uppercase tracking-[0.2em] mb-1">Index {ep.number}</div>
                               <div className="text-[11px] font-bold truncate text-slate-300 group-hover:text-white">{ep.title}</div>
                             </div>
                             <div className="absolute top-0 right-0 p-3 opacity-0 group-hover:opacity-100 transition-opacity">
                               <PlayIcon size={12} className="text-blue-500" />
                             </div>
                           </button>
                         ))}
                       </div>

                       {displayedEpisodes.length < allEpisodes.length && (
                         <button 
                           onClick={loadMoreEpisodes}
                           className="w-full py-6 bg-slate-900/40 hover:bg-slate-800 border-2 border-dashed border-white/10 rounded-2xl text-slate-500 text-[10px] font-black uppercase tracking-[0.4em] transition-all hover:border-blue-500/40 hover:text-blue-400 group relative"
                           disabled={isAppending}
                         >
                           {isAppending ? (
                             <span className="flex items-center justify-center gap-4">
                               <span className="w-4 h-4 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></span>
                               Synchronizing
                             </span>
                           ) : 'Expand Batch'}
                         </button>
                       )}
                     </div>
                   </div>
                </div>
              )}
            </div>

            {activeSource && (
              <div className="w-full lg:w-[400px] space-y-8 sticky top-28 self-start animate-in fade-in slide-in-from-right-4 duration-700">
                <div className="flex items-center justify-between px-2">
                  <h3 className="text-xs font-black uppercase tracking-[0.3em] text-slate-500">Up Next</h3>
                  <div className="px-2.5 py-1 bg-blue-600/10 rounded-lg">
                    <span className="text-[9px] text-blue-400 font-black uppercase tracking-widest">{displayedEpisodes.length} Loaded</span>
                  </div>
                </div>

                <div className="max-h-[calc(100vh-250px)] overflow-y-auto pr-4 space-y-4 custom-scrollbar">
                  {displayedEpisodes.map(ep => (
                    <button
                      key={ep.mal_id}
                      onClick={() => handleSelectEpisode(ep)}
                      className={`w-full group relative flex items-center gap-5 p-4 rounded-2xl transition-all border ${selectedEpisode?.mal_id === ep.mal_id ? 'bg-blue-600/10 border-blue-500/50 shadow-xl shadow-blue-500/10 translate-x-1' : 'bg-slate-900/40 border-transparent hover:bg-slate-800 hover:border-white/5'}`}
                    >
                      <div className={`w-14 h-14 flex-shrink-0 flex items-center justify-center rounded-2xl font-black text-sm transition-all ${selectedEpisode?.mal_id === ep.mal_id ? 'bg-blue-600 text-white scale-105' : 'bg-slate-800 text-slate-600 group-hover:bg-slate-700 group-hover:text-slate-400'}`}>
                        {ep.number}
                      </div>
                      <div className="text-left overflow-hidden">
                        <div className={`text-xs font-black uppercase tracking-tight truncate mb-1 transition-colors ${selectedEpisode?.mal_id === ep.mal_id ? 'text-blue-400' : 'text-slate-300 group-hover:text-white'}`}>
                          {ep.title}
                        </div>
                        <div className="flex items-center gap-2">
                          <span className="text-[9px] text-slate-600 font-black uppercase tracking-widest">Zone Network</span>
                          <span className="w-1 h-1 rounded-full bg-slate-800"></span>
                          <span className="text-[9px] text-slate-600 font-black uppercase tracking-widest">S1 E{ep.number}</span>
                        </div>
                      </div>
                      {selectedEpisode?.mal_id === ep.mal_id && (
                        <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-blue-500 rounded-r-full shadow-lg shadow-blue-500"></div>
                      )}
                    </button>
                  ))}

                  {displayedEpisodes.length < allEpisodes.length && (
                    <button 
                       onClick={loadMoreEpisodes}
                       className="w-full p-6 text-[9px] font-black uppercase tracking-[0.4em] text-slate-600 hover:text-blue-400 transition-all border-2 border-dashed border-white/5 rounded-2xl mt-4 hover:border-blue-500/40"
                       disabled={isAppending}
                    >
                      {isAppending ? 'Fetching...' : 'Load More'}
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        )}

        {!selectedAnime && !isSearching && (
          <div className="text-center py-48 max-w-3xl mx-auto space-y-12">
             <div className="relative inline-block group">
                <div className="absolute inset-0 bg-blue-500/30 blur-[100px] rounded-full group-hover:bg-blue-500/40 transition-all duration-1000 animate-pulse"></div>
                <div className="relative p-12 bg-slate-900 rounded-[3rem] border border-white/10 shadow-3xl transform group-hover:scale-105 transition-all duration-500">
                   <PlayIcon size={100} className="text-blue-500" />
                </div>
             </div>
             <div className="space-y-6">
               <h2 className="text-7xl font-black tracking-tighter leading-none">A New Era of <span className="bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-600">Streaming.</span></h2>
               <p className="text-slate-400 font-bold text-xl leading-relaxed max-w-2xl mx-auto uppercase tracking-wide opacity-80">Encrypted AES-128 Playback &bull; Zone Provider Integrated &bull; Batch Episode Sequencing</p>
             </div>
             <div className="flex items-center justify-center gap-8">
                <button onClick={() => {setSearchQuery('Bleach'); handleSearch();}} className="group relative bg-blue-600 hover:bg-blue-500 px-14 py-6 rounded-[2rem] text-xs font-black uppercase tracking-[0.3em] transition-all shadow-2xl shadow-blue-600/40 overflow-hidden">
                  <span className="relative z-10">Initialize Session</span>
                  <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-500"></div>
                </button>
                <button className="bg-white/5 hover:bg-white/10 px-14 py-6 rounded-[2rem] text-xs font-black uppercase tracking-[0.3em] transition-all border border-white/10 backdrop-blur-md">
                  Browse Hub
                </button>
             </div>
          </div>
        )}
      </main>

      <footer className="bg-slate-950 border-t border-white/5 py-12 text-center">
        <div className="container mx-auto px-4 space-y-4">
          <p className="text-[10px] text-slate-600 font-black uppercase tracking-[0.5em]">
            Zenith Network &bull; AES-128 Security Active &bull; {new Date().getFullYear()}
          </p>
          <div className="flex items-center justify-center gap-8 opacity-40">
             <span className="text-[8px] font-black uppercase tracking-widest text-slate-400">Jikan API</span>
             <span className="text-[8px] font-black uppercase tracking-widest text-slate-400">AniList GQL</span>
             <span className="text-[8px] font-black uppercase tracking-widest text-slate-400">Vidstack Engine</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import { SourcePlugin, SourceType, SourceResult } from '../types';

export const resolveSource = async (
  plugin: SourcePlugin,
  animeId: string,
  episodeNumber: number
): Promise<SourceResult> => {
  if (plugin.type === SourceType.EMBED) {
    // Added fallback to plugin.url and used new getVideoUrlTemplate property
    const url = (plugin.getVideoUrlTemplate || plugin.url)
      .replace('{animeId}', animeId)
      .replace('{episodeNumber}', episodeNumber.toString());

    // Fix: Added missing provider property
    return {
      url,
      type: SourceType.EMBED,
      provider: plugin.provider,
      pluginName: plugin.name,
      // Added missing label property
      label: plugin.label,
      category: plugin.category
    };
  }

  try {
    // In a real production app, we would use the plugin's getVideoUrlTemplate
    // For demo, we simulate fetching an HLS stream.
    // We use a known test HLS stream if the API fails
    const mockHls = 'https://test-streams.mux.dev/x36xhzz/x36xhzz.m3u8';

    // Fix: Added missing provider property
    return {
      url: mockHls,
      type: SourceType.DIRECT,
      provider: plugin.provider,
      pluginName: plugin.name,
      // Added missing label property
      label: plugin.label,
      category: plugin.category
    };
  } catch (e) {
    // Fix: Added missing provider property
    return {
      url: 'https://test-streams.mux.dev/x36xhzz/x36xhzz.m3u8',
      type: SourceType.DIRECT,
      provider: plugin.provider,
      pluginName: plugin.name,
      // Added missing label property
      label: plugin.label,
      category: plugin.category
    };
  }
};

