export default Player;

import React, { useRef, useState, useEffect, useMemo } from 'react';
// Import as namespace to avoid named export errors if they are missing in the current version
import * as Vidstack from '@vidstack/react';
import { defaultLayoutIcons, DefaultVideoLayout } from '@vidstack/react/player/layouts/default';
import Hls from 'hls.js';
import { SourceResult, SourceType } from '../types';

// Fix for missing types in some Vidstack versions by using any
type MediaPlayerInstance = any;
type MediaTimeUpdateEvent = any;
type MediaCanPlayEvent = any;
type MediaWaitingEvent = any;

// Extract components with robust fallbacks for missing exports in older/newer versions
const { MediaPlayer } = Vidstack as any;
// In some older versions, MediaProvider was called MediaOutlet, or it might be missing from named exports
const MediaProvider = (Vidstack as any).MediaProvider || (Vidstack as any).MediaOutlet || 'media-provider';
const Poster = (Vidstack as any).Poster || (Vidstack as any).MediaPoster || 'media-poster';

interface PlayerProps {
  source: SourceResult;
  title: string;
  poster?: string;
  onProgress: (percent: number) => void;
  onComplete: () => void;
}

type LoadingStage = 'initial' | 'fetching' | 'decrypting' | 'buffering' | 'ready';

const STAGE_CONFIG: Record<LoadingStage, { label: string; color: string; subtext: string }> = {
  initial: { label: 'Initializing Player', color: 'border-blue-500', subtext: 'Preparing playback environment' },
  fetching: { label: 'Fetching Playlist', color: 'border-cyan-400', subtext: 'Retrieving stream manifests' },
  decrypting: { label: 'Decrypting Source', color: 'border-purple-500', subtext: 'Validating AES-128 handshake' },
  buffering: { label: 'Buffering Video', color: 'border-indigo-500', subtext: 'Populating media buffers' },
  ready: { label: 'Ready', color: 'border-green-500', subtext: 'Playback initialized' },
};

const Player: React.FC<PlayerProps> = ({ source, title, poster, onProgress, onComplete }) => {
  const playerRef = useRef<MediaPlayerInstance>(null);
  const [stage, setStage] = useState<LoadingStage>('initial');
  const [lastTime, setLastTime] = useState(0);

  // Reset stage when source changes
  useEffect(() => {
    setStage('initial');
    if (playerRef.current && lastTime > 0) {
      const timer = setTimeout(() => {
        if (playerRef.current) playerRef.current.currentTime = lastTime;
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [source.url]);

  // Handle time updates for progress tracking
  const handleTimeUpdate = (event: MediaTimeUpdateEvent) => {
    if (!event?.detail) return;
    const { currentTime, duration } = event.detail;
    if (duration > 0) {
      setLastTime(currentTime);
      const percent = (currentTime / duration) * 100;
      onProgress(percent);
      if (percent >= 90) onComplete();
    }
  };

  const handleCanPlay = (event: MediaCanPlayEvent) => {
    setStage('ready');
  };

  const handleWaiting = (event: MediaWaitingEvent) => {
    if (stage === 'ready') setStage('buffering');
  };

  // Advanced HLS Configuration for decryption and CORS bypassing
  const hlsConfig = useMemo(() => ({
    // Use fetchSetup for modern proxying logic (hls.js v1.3+)
    fetchSetup: (url: string, init: RequestInit) => {
      const isManifest = url.includes('.m3u8');
      const isKey = url.includes('.key') || url.includes('/keys/');

      if (isManifest || isKey) {
        // Log decryption attempts for debugging
        if (isKey) setStage('decrypting');
        else if (stage === 'initial') setStage('fetching');

        // Reliable proxy for bypassing CORS on manifest/key fetches
        const proxyBase = 'https://test.cors.workers.dev/?';
        return new Request(proxyBase + encodeURIComponent(url), init);
      }

      // Pass through for segments (.ts) to avoid overhead
      return new Request(url, init);
    },
    xhrSetup: (xhr: XMLHttpRequest, url: string) => {
      // Secondary fallback for older versions or specific key scenarios
      if (url.includes('.key')) {
        xhr.withCredentials = false;
        // Intercept XHR lifecycle to update UI
        xhr.addEventListener('loadstart', () => setStage('decrypting'));
      }
    },
    // Robustness configs
    enableWorker: true,
    lowLatencyMode: true,
    backBufferLength: 90,
    manifestLoadingMaxRetry: 4,
    levelLoadingMaxRetry: 4,
  }), [source.url, stage]);

  const currentStageInfo = STAGE_CONFIG[stage];

  if (source.type === SourceType.EMBED) {
    return (
      <div className="relative aspect-video w-full bg-black rounded-xl overflow-hidden shadow-2xl">
        <iframe
          src={source.url}
          className="w-full h-full border-0"
          allowFullScreen
          referrerPolicy="no-referrer"
          sandbox="allow-scripts allow-same-origin"
        />
        <div className="absolute top-4 left-4 bg-slate-950/80 backdrop-blur-md px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-white/90 border border-white/10 shadow-lg">
          Source: <span className="text-blue-400">{source.provider}</span> ({source.category})
        </div>
      </div>
    );
  }

  return (
    <div className="relative aspect-video w-full bg-black rounded-xl overflow-hidden shadow-2xl group border border-white/5">
      {/* Dynamic Feedback Loader Overlay */}
      {stage !== 'ready' && (
        <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/90 backdrop-blur-xl transition-all duration-500">
          <div className="relative w-24 h-24">
            {/* Outer Background Ring */}
            <div className="absolute inset-0 border-4 border-white/5 rounded-full"></div>

            {/* Stage-driven Animated Rings */}
            <div className={`absolute inset-0 border-4 ${currentStageInfo.color} border-t-transparent rounded-full animate-spin transition-colors duration-700 shadow-[0_0_15px_rgba(59,130,246,0.3)]`}></div>
            <div className={`absolute inset-3 border-2 ${currentStageInfo.color} border-b-transparent rounded-full animate-spin-slow opacity-30`}></div>

            {/* Central Icon */}
            <div className="absolute inset-0 flex items-center justify-center">
              <div className={`w-2 h-2 rounded-full ${currentStageInfo.color.replace('border-', 'bg-')} animate-ping`}></div>
            </div>
          </div>

          <div className="mt-8 flex flex-col items-center gap-2 text-center">
            <h4 className={`text-xs font-black uppercase tracking-[0.5em] ${currentStageInfo.color.replace('border-', 'text-')} transition-colors duration-700`}>
              {currentStageInfo.label}
            </h4>
            <p className="text-[9px] font-bold text-slate-500 uppercase tracking-[0.2em] transition-opacity duration-300">
              {currentStageInfo.subtext}
            </p>
          </div>

          {/* Progress Bar (Simulated or estimated) */}
          <div className="mt-8 w-48 h-0.5 bg-white/5 rounded-full overflow-hidden">
             <div className={`h-full ${currentStageInfo.color.replace('border-', 'bg-')} transition-all duration-1000 ease-out`} style={{ 
               width: stage === 'initial' ? '20%' : stage === 'fetching' ? '45%' : stage === 'decrypting' ? '75%' : '90%' 
             }}></div>
          </div>
        </div>
      )}

      {/* Floating Meta Label */}
      <div className="absolute top-4 left-4 z-40 bg-slate-950/60 backdrop-blur-md px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-white/90 border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
        Source: <span className="text-blue-400">{source.provider}</span> ({source.category})
      </div>

      <MediaPlayer
        ref={playerRef}
        title={title}
        src={source.url}
        onTimeUpdate={handleTimeUpdate}
        onEnded={onComplete}
        onCanPlay={handleCanPlay}
        onWaiting={handleWaiting}
        onLoading={() => setStage('initial')}
        crossOrigin
        playsInline
        className={`w-full h-full transition-opacity duration-700 ${stage === 'ready' ? 'opacity-100' : 'opacity-0'}`}
      >
        <MediaProvider {...({ hlsConfig } as any)}>
          {poster && <Poster src={poster} alt={title} className="vds-poster object-cover w-full h-full" />}
        </MediaProvider>
        <DefaultVideoLayout icons={defaultLayoutIcons} />
      </MediaPlayer>

      <style>{`
        .animate-spin-slow {
          animation: spin 3s linear infinite;
        }
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
