// Fix for missing types in some Vidstack versions by using any
type MediaPlayerInstance = any;
type MediaTimeUpdateEvent = any;
type MediaCanPlayEvent = any;
type MediaWaitingEvent = any;

const { MediaPlayer } = Vidstack as any;
const MediaProvider = (Vidstack as any).MediaProvider || (Vidstack as any).MediaOutlet || 'div';
const Poster = (Vidstack as any).Poster || (Vidstack as any).MediaPoster || 'div';

interface PlayerProps {
  source: SourceResult;
  title: string;
  poster?: string;
  onProgress: (percent: number) => void;
  onComplete: () => void;
}

type LoadingStage = 'initial' | 'fetching' | 'decrypting' | 'buffering' | 'ready';

const STAGE_CONFIG: Record<LoadingStage, { label: string; color: string; subtext: string; progress: number }> = {
  initial: { label: 'Initializing Player', color: 'text-blue-500', subtext: 'Preparing core engine', progress: 20 },
  fetching: { label: 'Fetching Playlist', color: 'text-cyan-400', subtext: 'Retrieving stream segments', progress: 45 },
  decrypting: { label: 'Decrypting Source', color: 'text-purple-500', subtext: 'AES-128 handshake in progress', progress: 75 },
  buffering: { label: 'Buffering Video', color: 'text-indigo-500', subtext: 'Populating media buffers', progress: 90 },
  ready: { label: 'Ready', color: 'text-green-500', subtext: 'Stream synchronized', progress: 100 },
};

const Player: React.FC<PlayerProps> = ({ source, title, poster, onProgress, onComplete }) => {
  const playerRef = useRef<MediaPlayerInstance>(null);
  const [stage, setStage] = useState<LoadingStage>('initial');
  const [lastTime, setLastTime] = useState(0);

  // Preserve playback position on source change
  useEffect(() => {
    setStage('initial');
    if (playerRef.current && lastTime > 0) {
      const timer = setTimeout(() => {
        if (playerRef.current) playerRef.current.currentTime = lastTime;
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [source.url]);

  const handleTimeUpdate = (event: MediaTimeUpdateEvent) => {
    if (!event?.detail) return;
    const { currentTime, duration } = event.detail;
    if (duration > 0) {
      setLastTime(currentTime);
      const percent = (currentTime / duration) * 100;
      onProgress(percent);
      if (percent >= 90) onComplete();
    }
  };

  const handleCanPlay = (event: MediaCanPlayEvent) => {
    setStage('ready');
  };

  const handleWaiting = (event: MediaWaitingEvent) => {
    if (stage === 'ready') setStage('buffering');
  };

  // Robust HLS configuration for Decryption and CORS
  const hlsConfig = useMemo(() => {
    if (!Hls.isSupported()) return {};

    return {
      // fetchSetup is the preferred way in modern hls.js to handle requests
      fetchSetup: (url: string, init: RequestInit) => {
        const isManifest = url.includes('.m3u8');
        const isKey = url.includes('.key') || url.includes('/keys/');
        const isSegment = url.includes('.ts');

        // Logic to detect decryption stage
        if (isKey) setStage('decrypting');
        else if (isManifest && stage === 'initial') setStage('fetching');

        // Proxy .m3u8, .ts, and .key files to bypass CORS
        if (isManifest || isKey || isSegment) {
          const proxyBase = 'https://test.cors.workers.dev/?';
          const proxiedUrl = proxyBase + encodeURIComponent(url);
          return new Request(proxiedUrl, init);
        }

        return new Request(url, init);
      },
      // Retry logic for key fetch failures
      manifestLoadingMaxRetry: 3,
      levelLoadingMaxRetry: 3,
      fragLoadingMaxRetry: 6,
      enableWorker: true,
      lowLatencyMode: true,
    };
  }, [source.url]);

  const currentStageInfo = STAGE_CONFIG[stage];

  if (source.type === SourceType.EMBED) {
    return (
      <div className="relative aspect-video w-full bg-black rounded-xl overflow-hidden shadow-2xl">
        <iframe
          src={source.url}
          className="w-full h-full border-0"
          allowFullScreen
          referrerPolicy="no-referrer"
          sandbox="allow-scripts allow-same-origin"
        />
        <div className="absolute top-4 left-4 bg-slate-950/80 backdrop-blur-md px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-white/90 border border-white/10 shadow-lg">
          Source: <span className="text-blue-400">{source.provider}</span> (Embed)
        </div>
      </div>
    );
  }

  return (
    <div className="relative aspect-video w-full bg-black rounded-xl overflow-hidden shadow-2xl group border border-white/5">
      {/* Interactive Feedback Loader */}
      {stage !== 'ready' && (
        <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/95 backdrop-blur-2xl transition-all duration-700">
          <div className="relative w-32 h-32 flex items-center justify-center">
            {/* Background Track */}
            <svg className="absolute inset-0 w-full h-full -rotate-90">
              <circle
                cx="64"
                cy="64"
                r="58"
                fill="transparent"
                stroke="currentColor"
                strokeWidth="4"
                className="text-white/5"
              />
              {/* Animated Progress Ring */}
              <circle
                cx="64"
                cy="64"
                r="58"
                fill="transparent"
                stroke="currentColor"
                strokeWidth="4"
                strokeDasharray={364.4}
                strokeDashoffset={364.4 - (364.4 * currentStageInfo.progress) / 100}
                strokeLinecap="round"
                className={`${currentStageInfo.color} transition-all duration-1000 ease-in-out`}
              />
            </svg>

            {/* Inner pulsing core */}
            <div className={`w-12 h-12 rounded-full ${currentStageInfo.color.replace('text-', 'bg-')} opacity-20 animate-ping absolute`}></div>
            <div className={`w-12 h-12 rounded-full ${currentStageInfo.color.replace('text-', 'bg-')} opacity-40 blur-md`}></div>
            <div className="absolute font-black text-xs text-white opacity-40">{currentStageInfo.progress}%</div>
          </div>

          <div className="mt-10 flex flex-col items-center gap-2 text-center">
            <h4 className={`text-sm font-black uppercase tracking-[0.6em] ${currentStageInfo.color} transition-colors duration-500`}>
              {currentStageInfo.label}
            </h4>
            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] animate-pulse">
              {currentStageInfo.subtext}
            </p>
          </div>
        </div>
      )}

      {/* Floating Source Meta */}
      <div className="absolute top-4 left-4 z-40 bg-slate-950/70 backdrop-blur-md px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-white/90 border border-white/10 shadow-xl opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
        Source: <span className="text-blue-400">Zone (Hardsub)</span>
      </div>

      <MediaPlayer
        ref={playerRef}
        title={title}
        src={source.url}
        onTimeUpdate={handleTimeUpdate}
        onEnded={onComplete}
        onCanPlay={handleCanPlay}
        onWaiting={handleWaiting}
        onLoading={() => setStage('initial')}
        crossOrigin
        playsInline
        className={`w-full h-full transition-opacity duration-1000 ${stage === 'ready' ? 'opacity-100' : 'opacity-0'}`}
      >
        <MediaProvider {...({ hlsConfig } as any)}>
          {poster && <Poster src={poster} alt={title} className="vds-poster object-cover w-full h-full" />}
        </MediaProvider>
        <DefaultVideoLayout icons={defaultLayoutIcons} />
      </MediaPlayer>

      <style>{`
        .vds-poster {
          position: absolute;
          inset: 0;
          opacity: 0.3;
          filter: blur(20px);
          transition: opacity 1s ease;
        }
        .vds-media-player[data-can-play] .vds-poster {
          opacity: 0;
        }
      `}</style>
    </div>
  );
};

