        if (playerRef.current) playerRef.current.currentTime = lastTime;
      }, 300);
      return () => clearTimeout(timer);
    }
  }, [source.url]);

  const handleTimeUpdate = (event: MediaTimeUpdateEvent) => {
    if (!event?.detail) return;
    const { currentTime, duration } = event.detail;
    if (duration > 0) {
      setLastTime(currentTime);
      const percent = (currentTime / duration) * 100;
      onProgress(percent);
      if (percent >= 90) onComplete();
    }
  };

  const handleCanPlay = () => setStage('ready');
  const handleWaiting = () => {
    if (stage === 'ready') setStage('buffering');
  };

  const hlsConfig = useMemo(() => {
    if (!Hls.isSupported()) return {};

    return {
      fetchSetup: (url: string, init: RequestInit) => {
        const isManifest = url.includes('.m3u8');
        const isKey = url.includes('.key') || url.includes('/keys/');
        const isSegment = url.includes('.ts');

        // Update UI state based on request type
        if (isKey) {
          setStage('decrypting');
        } else if (isManifest && stage === 'initial') {
          setStage('fetching');
        }

        // Dedicated Proxy for CORS-restricted assets (Manifests, Keys, Segments)
        // This ensures the AES-128 key is loaded without browser security blocks
        if (isManifest || isKey || isSegment) {
          const proxyBase = 'https://test.cors.workers.dev/?';
          return new Request(proxyBase + encodeURIComponent(url), init);
        }

        return new Request(url, init);
      },
      // Hls.js performance and robustness tuning
      enableWorker: true,
      lowLatencyMode: true,
      backBufferLength: 60,
      maxBufferLength: 30,
      manifestLoadingMaxRetry: 5,
      levelLoadingMaxRetry: 5,
      xhrSetup: (xhr: XMLHttpRequest, url: string) => {
        if (url.includes('.key')) {
          xhr.withCredentials = false; // Required for some CDN key delivery
        }
      }
    };
  }, [source.url]);

  const config = STAGE_CONFIG[stage];

  if (source.type === SourceType.EMBED) {
    return (
      <div className="relative aspect-video w-full bg-black rounded-xl overflow-hidden shadow-2xl border border-white/5">
        <iframe
          src={source.url}
          className="w-full h-full border-0"
          allowFullScreen
          referrerPolicy="no-referrer"
          sandbox="allow-scripts allow-same-origin"
        />
        <div className="absolute top-4 left-4 bg-slate-950/80 backdrop-blur-md px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-white/90 border border-white/10 shadow-lg">
          Source: <span className="text-blue-400">Zone (External)</span>
        </div>
      </div>
    );
  }

  return (
    <div className="relative aspect-video w-full bg-black rounded-xl overflow-hidden shadow-2xl group border border-white/5 transition-all">
      {/* Interactive Feedback Circle Loader */}
      {stage !== 'ready' && (
        <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/98 backdrop-blur-3xl transition-opacity duration-700">
          <div className="relative w-40 h-40 flex items-center justify-center">
            {/* Background SVG Circle */}
            <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 100 100">
              <circle
                cx="50"
                cy="50"
                r="45"
                fill="transparent"
                stroke="currentColor"
                strokeWidth="2"
                className="text-white/5"
              />
              {/* Animated Stage Progress Ring */}
              <circle
                cx="50"
                cy="50"
                r="45"
                fill="transparent"
                stroke="currentColor"
                strokeWidth={config.ringSize}
                strokeDasharray="282.7"
                strokeDashoffset={282.7 - (282.7 * config.progress) / 100}
                strokeLinecap="round"
                className={`${config.color} transition-all duration-1000 ease-in-out shadow-[0_0_20px_rgba(59,130,246,0.3)]`}
              />
            </svg>

            {/* Inner pulsing core visual */}
            <div className="flex flex-col items-center justify-center">
               <div className={`w-3 h-3 rounded-full ${config.color.replace('text-', 'bg-')} animate-ping absolute`}></div>
               <div className={`w-10 h-10 rounded-full ${config.color.replace('text-', 'bg-')} opacity-10 blur-xl`}></div>
               <span className="text-[10px] font-black text-white/40 mt-1">{config.progress}%</span>
            </div>
          </div>

          <div className="mt-12 flex flex-col items-center gap-3 text-center px-6">
            <h4 className={`text-sm font-black uppercase tracking-[0.6em] ${config.color} transition-colors duration-700 drop-shadow-sm`}>
              {config.label}
            </h4>
            <div className="flex items-center gap-3">
               <div className="w-1.5 h-1.5 rounded-full bg-slate-800 animate-bounce [animation-delay:-0.3s]"></div>
               <p className="text-[9px] font-bold text-slate-500 uppercase tracking-[0.3em]">
                 {config.subtext}
               </p>
               <div className="w-1.5 h-1.5 rounded-full bg-slate-800 animate-bounce [animation-delay:-0.15s]"></div>
            </div>
          </div>
        </div>
      )}

      {/* Floating Network Badge */}
      <div className="absolute top-4 left-4 z-40 bg-slate-950/80 backdrop-blur-md px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-white/90 border border-white/10 shadow-2xl opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
        Source: <span className="text-blue-400">Zone (Hardsub)</span>
      </div>

      <MediaPlayer
        ref={playerRef}
        title={title}
        src={source.url}
        onTimeUpdate={handleTimeUpdate}
        onEnded={onComplete}
        onCanPlay={handleCanPlay}
        onWaiting={handleWaiting}
        onLoading={() => setStage('initial')}
        crossOrigin
        playsInline
        className={`w-full h-full transition-opacity duration-1000 ${stage === 'ready' ? 'opacity-100' : 'opacity-0'}`}
      >
        <MediaProvider {...({ hlsConfig } as any)}>
          {poster && <Poster src={poster} alt={title} className="vds-poster" />}
        </MediaProvider>
        <DefaultVideoLayout icons={defaultLayoutIcons} />
      </MediaPlayer>

      <style>{`
        .vds-poster {
          position: absolute;
          inset: 0;
          width: 100%;
          height: 100%;
          object-fit: cover;
          opacity: 0.2;
          filter: blur(40px);
          transition: opacity 1.5s ease;
        }
        .vds-media-player[data-can-play] .vds-poster {
          opacity: 0;
          pointer-events: none;
        }
        vds-media-player {
          background-color: transparent !important;
        }
      `}</style>
    </div>
  );
};

export default Player;
